import{_ as a,p as n,q as s,Y as i}from"./framework-aa5c4115.js";const e={},t=i(`<h1 id="函数式编程" tabindex="-1"><a class="header-anchor" href="#函数式编程" aria-hidden="true">#</a> 函数式编程</h1><p>函数式编程是种编程方式，它将电脑运算视为函数的计算。</p><p>函数式编程是面向数学的抽象，将计算描述为一种<strong>表达式求值</strong>，其实，函数式程序就是一个<strong>表达式。</strong></p><p>核心概念：</p><ul><li>数据不可变： 它要求你所有的数据都是不可变的，这意味着如果你想修改一个对象，那你应该创建一个新的对象用来修改，而不是修改已有的对象。</li><li>无状态：主要是强调对于一个函数，不管你何时运行，它都应该像第一次运行一样，给定相同的输入，给出相同的输出，完全不依赖外部状态的变化。</li></ul><p>函数式编程提出函数应该具备的特性：==没有副作用==和==纯函数==。</p><h2 id="函数式编程的特点" tabindex="-1"><a class="header-anchor" href="#函数式编程的特点" aria-hidden="true">#</a> 函数式编程的特点</h2><ul><li>函数是&quot;一等公民&quot;</li><li>声明式编程</li><li>惰性执行(不产生无意义的中间变量)</li><li>无状态和数据不可变</li><li>没有副作用</li><li>纯函数(<strong>相同的输入，永远会得到相同的输出</strong>)</li></ul><h2 id="柯里化" tabindex="-1"><a class="header-anchor" href="#柯里化" aria-hidden="true">#</a> 柯里化</h2><p>柯里化的意思是将一个多元函数，转换成一个依次调用的<strong>单元函数</strong>。</p><p>柯里化处理的结果刚好就是<strong>单输入</strong>的。</p><div class="language-scss line-numbers-mode" data-ext="scss"><pre class="language-scss"><code><span class="token function">f</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span>b<span class="token punctuation">,</span>c<span class="token punctuation">)</span> → <span class="token function">f</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">(</span>c<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="函数组合" tabindex="-1"><a class="header-anchor" href="#函数组合" aria-hidden="true">#</a> 函数组合</h2><p>函数组合的目的是将多个函数组合成一个函数。</p><p>函数组合的好处显而易见，它让代码变得简单而富有可读性，同时通过不同的组合方式，我们可以轻易组合出其他常用函数，让我们的代码更具表现力。</p><p>大型的程序，都可以通过这样一步步的拆分组合实现，而剩下要做的，就是去构造足够多的积木块（函数）。</p><h2 id="优缺点" tabindex="-1"><a class="header-anchor" href="#优缺点" aria-hidden="true">#</a> 优缺点</h2><p>优点：</p><ul><li>代码简洁，开发快速</li><li>接近自然语言，易于理解</li><li>易于&quot;并发编程&quot;</li><li>更少的出错概率</li></ul><p>缺点：</p><ul><li>性能开销</li><li>资源占用</li><li>递归陷阱</li></ul>`,21),l=[t];function c(p,o){return n(),s("div",null,l)}const u=a(e,[["render",c],["__file","hanshushibiancheng.html.vue"]]);export{u as default};
